sql:
SELECT observation_id, year, gmsl_m
FROM gmsl_observations
WHERE validation_status = 'unvalidated' AND year > 2000;

SELECT gmsl_m 
FROM gmsl_observations
ORDER BY year DESC;

SELECT year, AVG(gmsl_m) AS average_gmsl_m
FROM gmsl_observations
GROUP BY year;

SELECT COUNT(observation_id) AS observation_count
FROM uncertainty_analysis
WHERE uncertainty_value > (SELECT AVG(uncertainty_value) FROM uncertainty_analysis);

SELECT source_ids, average_gmsl_m
FROM aggregated_data
ORDER BY source_ids;

SELECT COUNT(observation_id) 
FROM gmsl_observations 
WHERE type_data = 'observation';

SELECT COUNT(*)
FROM data_ingestion_logs
WHERE status = 'success';

SELECT source_name 
FROM data_sources
WHERE source_id NOT IN (SELECT source_id FROM gmsl_observations);

external_knowledge:
- 'Beacons' metaphorically refer to data sources;
- 'Longest shadows' symbolize high uncertainty values;
- 'Verified data' refers to observations with a validation status of 'validated'.

sql:
SELECT validator_id, AVG(validation_score) AS average_validation_score
FROM validation_logs
GROUP BY validator_id;

SELECT observation_id, AVG(uncertainty_value) AS average_uncertainty_value
FROM uncertainty_analysis
GROUP BY observation_id;

SELECT source_id, strftime('%Y', ingestion_date) AS ingestion_year, COUNT(*) AS ingestion_logs_count
FROM data_ingestion_logs
GROUP BY source_id, ingestion_year;

external_knowledge:
- The year might partially include a decimal to indicate the midpoint of a year. ;
- Validation results typically signify the outcome of the validation process, such as whether the data meets certain criteria or not. ;
- The average validation score gives an indication of the overall reliability or accuracy of the validations for a given year.

sql:
SELECT AVG(gmsl_m) AS average_gmsl_m
FROM gmsl_observations
WHERE type_data = 'model prediction';
